import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-ChtuvW5g.js";var s={class:`ant-doc vp-doc`},c=a({__name:`contributing.zh-CN`,setup(a,{expose:c}){let l={title:`贡献指南`,frontmatter:{title:`贡献指南`},headers:[{level:2,title:`行为准则`,slug:`行为准则`,link:`#行为准则`,children:[]},{level:2,title:`开发透明`,slug:`开发透明`,link:`#开发透明`,children:[]},{level:2,title:`分支管理`,slug:`分支管理`,link:`#分支管理`,children:[]},{level:2,title:`第一次贡献`,slug:`第一次贡献`,link:`#第一次贡献`,children:[]},{level:2,title:`Pull Request`,slug:`pull-request`,link:`#pull-request`,children:[]},{level:2,title:`开发流程`,slug:`开发流程`,link:`#开发流程`,children:[]},{level:2,title:`致谢`,slug:`致谢`,link:`#致谢`,children:[]}],description:``},u={title:`贡献指南`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>这篇指南会帮助你了解如何为 ProComponents of Vue 贡献一份自己的力量，请你在提issue 或者 pull request 之前花几分钟来阅读一遍这篇指南。</p><h2 id="行为准则" tabindex="-1">行为准则 <a class="header-anchor" href="#行为准则" aria-label="Permalink to &quot;行为准则&quot;">​</a></h2><p>我们使用了与Ant Design社区相同的<a href="https://github.com/antdv-next/antdv-next/blob/main/CODE_OF_CONDUCT.md">行为准则</a>, 希望所有的贡献者都能遵守，请花时间阅读一遍全文以确保你能明白哪些是可以做的，哪些是不能做的。</p><h2 id="开发透明" tabindex="-1">开发透明 <a class="header-anchor" href="#开发透明" aria-label="Permalink to &quot;开发透明&quot;">​</a></h2><p>我们所有的开发工作都是在<a href="https://github.com/antdv-next/antdv-next">Github</a>上进行的。不管是团队成员还是社区贡献者的 pull request 都需要经过同样的流程 review。</p><h2 id="分支管理" tabindex="-1">分支管理 <a class="header-anchor" href="#分支管理" aria-label="Permalink to &quot;分支管理&quot;">​</a></h2><p>我们目前长期维护两个分支<code>main</code>和<code>feat</code>。如果你需要修复一个bug，那么请发 pull request 到 main，每隔一段时间(最长一个月)我们从<code>main</code>发布一个<code>patch</code>版本;如果你需要添加一个新功能的 pull request,那么请基于<code>feat</code>分支来做，我们尽可能的会在两个月内从<code>feat</code>合并到<code>main</code>，并发布一个包含新特性的<code>minor</code>版本。</p><div class="info custom-block"><p class="custom-block-title">为什么周期不确定？</p><p>我们无法像 Ant Design 那样有一个庞大的团队来支持频繁的版本发布，所以我们只能尽可能的在保证质量的前提下，尽快的发布新版本。希望大家理解。</p></div><h2 id="第一次贡献" tabindex="-1">第一次贡献 <a class="header-anchor" href="#第一次贡献" aria-label="Permalink to &quot;第一次贡献&quot;">​</a></h2><p>如果你还不清楚怎么在 GitHub 上提 Pull Request ，可以阅读下面这篇文章来学习：</p><p><a href="https://segmentfault.com/a/1190000000736629">如何优雅地在 GitHub 上贡献代码</a></p><p>为了能帮助你开始你的第一次尝试，我们用 <a href="https://github.com/antdv-next/antdv-next/issues?q=is%3Aissue+is%3Aopen+label%3A%22good+first+issue%22">good first issues</a> 标记了一些比较容易修复的 bug 和小功能。这些 issue 可以很好地作为你的首次尝试。</p><p>如果你打算开始处理一个 issue，请先检查一下 issue 下面的留言以确保没有别人正在处理这个 issue。如果当前没有人在处理的话你可以留言告知其他人你将会处理这个 issue，以免别人重复劳动。</p><p>如果之前有人留言说会处理这个 issue 但是一两个星期都没有动静，那么你也可以接手处理这个 issue，当然还是需要留言告知其他人。</p><h2 id="pull-request" tabindex="-1">Pull Request <a class="header-anchor" href="#pull-request" aria-label="Permalink to &quot;Pull Request&quot;">​</a></h2><p>ProComponents of Vuents of Vue Team 会关注所有的 pull request，我们会 review 以及合并你的代码，也有可能要求你做一些修改或者告诉你我们为什么不能接受这样的修改。</p><p><strong>在你发送 Pull Request 之前</strong>，请确认你是按照下面的步骤来做的：</p><ol><li>基于 <a href="#%E5%88%86%E6%94%AF%E7%AE%A1%E7%90%86">正确的分支</a> 做修改。</li><li>在项目根目录下运行了 <code>pnpm install</code>。</li><li>如果你修复了一个 bug 或者新增了一个功能，请确保编写了相应的测试，这很重要。</li></ol><p>由于antdv-next的大部分是基于<code>vue-components</code>的，所以有时候你需要给<a href="https://github.com/antdv-next/vue-components">vue-components</a>仓库发送一个 pull request。如果你修复了某个bug，那么我们在合并你的修改后会尽快发布一个patch版本，然后你只要重新安装你的依赖就可以使用新发布的版本了。如果你的 pull request 是新增了某个功能，那么在你的修改合并并且发布版本后，你还需要发送一个 pull request 到 ProComponents of Vuents of Vue 来升级响应的依赖、文档以及Typescript类型定义。</p><h2 id="开发流程" tabindex="-1">开发流程 <a class="header-anchor" href="#开发流程" aria-label="Permalink to &quot;开发流程&quot;">​</a></h2><p>我们项目默认是一个 monorepo 仓库，使用 <a href="https://pnpm.io/workspaces">pnpm workspace</a> 来管理多个子包(package)，所以在你开始贡献代码之前，请确保你已经了解了 pnpm workspace 的基本使用方法。</p><p>所以下面的步骤假设你已经安装并且配置好了 pnpm。</p><ol><li>Fork 这个仓库到你的个人账号下。</li><li>克隆你 Fork 的仓库到本地：<code>git clone https://github.com/xxx/antdv-next.git</code>。</li><li>进入项目目录：<code>cd antdv-next</code>。</li><li>安装依赖：<code>pnpm install</code>。</li><li>运行开发环境：<code>pnpm dev</code>。</li><li>运行代码风格检查：<code>pnpm lint</code>。</li><li>站点构建：<code>pnpm build</code>。</li><li>编译构建：<code>pnpm build:antdv</code></li></ol><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><p>感谢所有为ProComponents of Vuents of Vue 贡献代码和文档的朋友们，是你们让这个项目变得更好！我们期待更多的贡献者加入到这个ProComponents of VueProComponents of Vue 的发展。</p><a href="https://github.com/antdv-next/antdv-next/graphs/contributors"><img src="https://contrib.rocks/image?repo=antdv-next/antdv-next&amp;max=100&amp;columns=15"></a>`,26)]]))}});export{c as default};